                        <button
                          onClick={(ev) => {
                            ev.stopPropagation();
                            openEdit(e);
                          }}
                          className="p-2 rounded-lg hover:bg-gray-100"
                          title="Edit"
                        >
                          <Pencil className="w-5 h-5 text-gray-700" />
                        </button>
                      </td>
                    ) : null}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      ) : (
