              "/Main_Modules/Resigned/"
            )}`;

            return (
              <div
                key={e.applicant_id}
                role={sessionRole !== "employee" ? "button" : undefined}
                tabIndex={sessionRole !== "employee" ? 0 : -1}
                onKeyDown={(ev) => {
                  if (sessionRole === "employee") return;
                  if (ev.key === "Enter" || ev.key === " ") {
                    ev.preventDefault();
                    router.push(detailsHref);
                  }
